var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"……내가 분명히 말했을 텐데, 코치?","JPN":"……言ったよね、コーチ。","ENG":"...Didn't I make myself clear, Coach?","TWN":"……我應該說得很清楚吧，教練？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"엔간히 중요한 일 아니면, 이 염병할 슈트 입고 있을 때는 호출하지 말라고.","JPN":"よほどの重要な案件でなければ、このクソスーツを着てる時には呼ぶなって。","ENG":"Unless it's something really important, don't call me when I'm in this damn suit.","TWN":"如果不是非常重要的事，就別在我穿著這該死的衣服時叫我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"지금, 이 꼴로 코치랑 단 둘이 여기 있는 거… 야한 오해 사기 딱 좋은 건 알고 있지……?","JPN":"今、この格好でコーチと2人きり……誤解してくださいって言ってるようなもんだよ……？","ENG":"You do realize that being alone with you while I'm dressed like this... is practically an open invitation for gossip, right...?","TWN":"現在，我這副模樣跟教練二個人獨處…你知道這很容易讓人誤會吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"큭큭, 괜찮겠어? 다른 직원들이 보면 어쩌려고?","JPN":"ククッ、いいの？　他の社員に見られたらどうするつもり？","ENG":"Keke, you sure you're okay with that? What if the other employees see us?","TWN":"呵呵，你沒關係嗎？要是被其他員工看到怎麼辦？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐? 상관없다고?","JPN":"は？　構わない？","ENG":"What? You don't care?","TWN":"什麼？你說你沒差？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"나 참, 그래도 사장인데 이미지 관리 좀 하시지?","JPN":"まったく、社長なんだから自分のイメージにちょっとは気を使いなよ。","ENG":"Come on, you're the Boss. Ever heard of reputation management?","TWN":"真是的，你好歹也是個老闆，要顧一下形象吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"하여간 보기보다 엉큼하다니깐…? 뭐, 그런 쿨한 점도 나름대로 매력적이지만 말이야…….","JPN":"外見に反して性悪なんだから……まあ、そんなクールなところもそれなりに魅力的なんだけど……","ENG":"Honestly, you're sneakier than you look... Though I guess that laid-back attitude is part of your charm...","TWN":"你確實一副深不可測的樣子…不過，這也算是你的魅力…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"크흠……!","JPN":"ごほん……！","ENG":"Ahem...!","TWN":"咳咳……！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그래서? 옷도 갈아입지 말고, 곧바로 사장실까지 오라니…….","JPN":"で？　着替えずに、すぐ社長室まで来いって……","ENG":"So? You had me come straight to your office without even letting me change...?","TWN":"所以呢？還叫我不用換衣服，直接來老闆辦公室…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐가 그렇게 급해서 이렇게 호들갑이실까?","JPN":"何をそんなに急ぐことがおありで？","ENG":"What's got you in such a rush?","TWN":"是有什麼急事，這樣急急忙忙把人找來？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐야, 이건…? 종신 계약서잖아……?","JPN":"なんだ、これ……？　終身契約書じゃないか……？","ENG":"Wait, is this... a lifetime contract...?","TWN":"什麼，這不是…？終身契約嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"고작 이런 걸로 날 부른 거야? 우리 사이에 이 정도는 당연히 오케이지.","JPN":"こんなことで呼び出したの？　私たちの仲なら、これくらい当然オッケーだよ。","ENG":"You called me all the way here for this? Come on, you know I'd say yes without hesitation.","TWN":"你叫我過來就是因為這個？以我們的關係，簽個合約完全OK吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이보다 더 한 것도 할 수 있는 걸?","JPN":"これよりすごいことだってできるし？","ENG":"Think this is the most I can do?","TWN":"我可以做的比這個還多呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"더한 게 뭐냐고? 글쎄? 아마도 그건 코치의 상상력에 따라 다르지 않을까?","JPN":"すごいことが何かって？　さあ？　それはコーチの想像力次第なんじゃないかな？","ENG":"What's more, you ask? Hmm, I guess that depends on how wild your imagination, Coach.","TWN":"做什麼喔？這個嘛？這就要看你的想像力囉？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"큭큭, 장난이야, 장난. 쑥맥처럼 왜 그래?","JPN":"ククッ、冗談だよ、冗談。なに顔赤らめてんの？","ENG":"Keke, I'm just messing with you. Why so stiff?","TWN":"呵呵，開玩笑的啦，開玩笑。你害羞什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"……난 말이야.","JPN":"……私ね。","ENG":"...You see.","TWN":"我的意思是……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"줄곧 남들이 휘둘리는 대로 살아왔어.","JPN":"ずっと言われるがままに生きてきたんだ。","ENG":"I've always lived by other people's rules.","TWN":"我一直以來都過著任人擺布的生活。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"참 빌어먹을 인생이었지. 스푸트니크에서도 그랬고, 맨션에서도 그래왔으니까.","JPN":"マジでくそみたいな人生だった。スプートニクでもそうだったし、マンションでもそう。","ENG":"What a screwed-up life. It was the same in Sputnik, same at Mansion.","TWN":"真是該死的人生。從史普尼克那時起就是這樣，在曼森時也是如此。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그렇게 무의미하게 살아왔는데… 우리 중에 마지막까지 살아남은 건, 결국 나 혼자더라……?","JPN":"そうやって何の意味もなく生きてきたのに……隊員の中で最後まで生き残ったのは、結局私1人だけ……","ENG":"I went through all that for nothing. And in the end... I was the only one left.","TWN":"就這樣過著毫無意義的生活…結果我們幾個之中，最後活下來的，竟然只有我一人…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐야, 코치. 지금 날 위로하려는 거야?","JPN":"なに、コーチ。今、私を慰めようとしてる？","ENG":"What now, Coach? Are you seriously trying to cheer me up?","TWN":"教練，你幹嘛？你現在是在安慰我嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"됐어. 뭘 이런 걸 가지고.","JPN":"やめてよ、これしきのことで。","ENG":"Forget it. This isn't something worth crying over.","TWN":"大可不必，這種事沒什麼好安慰的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"말했잖아. 나는 장전된 총이라고. 이제 와서 삶의 방식을 바꿀 생각은 추호도 없어.","JPN":"言っただろ？　私は装填済みの銃なんだって。今更生き方を変えるつもりなんてこれっぽちもない。","ENG":"I told you already. I'm a loaded gun, and I've got no plans to live any differently.","TWN":"我不是說過，我是上膛的槍。我一點都沒有想改變生活方式。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"하지만 코치랑 함께라면…….","JPN":"でもコーチと一緒なら……","ENG":"But if it's with you, Coach...","TWN":"但若是和教練一起…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"코치랑 함께라면… 틀림없이 그 지옥에서 나 혼자만 살아남은 이유를 찾을 수 있겠지…….","JPN":"コーチと一緒なら……きっとあの地獄から私1人だけ生き残った理由を見つけられると思うんだ……","ENG":"If it's with you... maybe I'll finally figure out why I was the only one who crawled out of that hell.","TWN":"若是和教練一起…我就一定能夠找到，只有我從地獄中活下來的理由…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐, 애초부터 나를 길들일 수 있는 사람은 이 세상에서 코치 정도밖에 없을 테니까.","JPN":"ま、そもそも私を手懐けられる人なんてこの世界にコーチくらいしかいないしね。","ENG":"Well, you're probably the only person in this world who could ever tame me.","TWN":"反正，在這個世界上能夠馴服我的人，由始至終都只有教練一個人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그러니까, 계약서를 줘.","JPN":"だから、契約書寄越しな。","ENG":"So, hand me that contract.","TWN":"把合約給我吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"코치가 뭘 원하든, 내 목숨 한 발 정도는 흔쾌히 걸어줄게.","JPN":"コーチが何を望もうが、私の命の一発くらい喜んでかけてやる。","ENG":"Whatever you're after, I'm in. I'll bet my life on it.","TWN":"只要是教練想要的，我都會毫不猶豫地成為你的子彈。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};